/*
=========================================================
WEDDING NODE (Merge Appended Branches)
- Sammelt gnd_result_string und Triage-Daten (rejected) ein
- Harmonisiert das Daten-Schema für SeaTable
- Erstellt genau EIN finales Output-Item
=========================================================
*/

const items = $input.all();

// 1. Variablen zum Einsammeln der Daten aus den verschiedenen Strängen
let gndString = "{}";
let rejectedData = {};
let topLevelMeta = {
    _decolonial_audit_log: null,
    Protokoll_Status: "Unknown",
    Kritischer_Hinweis: null
};

// 2. Alle eintreffenden Items durchsuchen (fangen den "Append" auf)
for (const item of items) {
    const json = item.json;

    // A: Hat dieses Item den GND-String?
    if (json.gnd_result_string) {
        gndString = json.gnd_result_string;
    }

    // B: Hat dieses Item die Triage-Ergebnisse?
    const currentRejected = json.payload_rejected || json.llm_result?.payload_rejected;

    if (currentRejected) {
        rejectedData = currentRejected;
        topLevelMeta._decolonial_audit_log = json._decolonial_audit_log || currentRejected._decolonial_audit_log;
        topLevelMeta.Protokoll_Status = json.Protokoll_Status || currentRejected.Protokoll_Status;
        topLevelMeta.Kritischer_Hinweis = json.Kritischer_Hinweis || currentRejected.Kritischer_Hinweis;
    }
}

// 3. Den GND-String zu einem echten JSON entpacken
let validatedData = {};
try {
    validatedData = JSON.parse(gndString);
} catch (e) {
    validatedData = {};
}

// 4. Das finale Output-Objekt vorbereiten
const finalOutput = {
    _decolonial_audit_log: topLevelMeta._decolonial_audit_log,
    Protokoll_Status: topLevelMeta.Protokoll_Status,
    Kritischer_Hinweis: topLevelMeta.Kritischer_Hinweis
};

const clusters = [
    "Objekttyp", "Thema_Phänomen", "Inhalt_Motiv", "Funktion_Zweck",
    "Visuelle_Merkmale", "Form_Gestalt", "Bestandteile", "Gebrauchskontext",
    "Kultureller_Kontext", "Emotion_Atmosphäre", "Farbe_Nuancen"
];

// 5. Cluster zusammenführen (Die eigentliche Hochzeit)
for (const cluster of clusters) {
    const mergedCluster = [];

    // A) Validierte Begriffe (GRÜN, aus dem GND-Strang)
    if (validatedData[cluster] && Array.isArray(validatedData[cluster])) {
        for (const validItem of validatedData[cluster]) {
            mergedCluster.push({
                term: validItem.term,
                status: "green", // hier kommen nur echte Grüne an
                gnd_name: validItem.gnd_name || null,
                gnd_id: validItem.gnd_id || null,
                confidence: validItem.confidence || null,
                llm2_rationale: validItem.llm2_rationale || null,
                llm3_judge_comment: validItem.llm3_judge_comment || null,
                llm4_reasoning: validItem.llm4_reasoning || null
            });
        }
    }

    // B) Zurückgehaltene Begriffe (GELB + ROT, aus dem Triage-Strang)
    if (rejectedData[cluster] && Array.isArray(rejectedData[cluster])) {
        for (const rejectedItem of rejectedData[cluster]) {
            mergedCluster.push({
                term: rejectedItem.term,
                status: rejectedItem.status || "red", // gelb bleibt gelb, rot bleibt rot
                gnd_name: null,
                gnd_id: null,
                confidence: null,
                llm2_rationale: rejectedItem.why || null,
                llm3_judge_comment: rejectedItem.judge_comment || null,
                llm4_reasoning: "Status nicht grün – zurückgehalten, kein GND-Abgleich durchgeführt."
            });
        }
    }

    finalOutput[cluster] = mergedCluster;
}

// 6. Wir geben exakt EIN Item zurück, das alles beinhaltet
return [{ json: finalOutput }];

/*
=========================================================
FLATTEN FOR SEATABLE (1 Item pro Schlagwort)
- Löst die Cluster auf
- Erstellt für jedes Schlagwort ein eigenes n8n-Item
- Vererbt das komplette Decolonial Audit Log an jedes Item
- Bereitet die Spaltennamen für SeaTable vor
=========================================================
*/

const items = $input.all();
const flattenedKeywords = [];

const clusters = [
    "Objekttyp", "Thema_Phänomen", "Inhalt_Motiv", "Funktion_Zweck",
    "Visuelle_Merkmale", "Form_Gestalt", "Bestandteile", "Gebrauchskontext",
    "Kultureller_Kontext", "Emotion_Atmosphäre", "Farbe_Nuancen"
];

for (const item of items) {
    const json = item.json;

    // Wir isolieren das Audit-Log (mit Fallback, falls es mal fehlen sollte)
    const auditLog = json._decolonial_audit_log || {};

    // Iteriere durch alle Cluster
    for (const cluster of clusters) {
        const keywordArray = json[cluster];

        // Wenn das Cluster existiert und befüllt ist...
        if (keywordArray && Array.isArray(keywordArray)) {
            for (const kw of keywordArray) {

                // Erstelle ein isoliertes Item für jedes einzelne Schlagwort
                flattenedKeywords.push({
                    json: {
                        // METADATEN DES OBJEKTS
                        // Objekt_ID: json.ID || "N/A",  <-- Objekt-Referenz für SeaTable
                        Protokoll_Status: json.Protokoll_Status || "Unknown",
                        Kritischer_Hinweis: json.Kritischer_Hinweis || "",

                        // DECOLONIAL AUDIT LOG (aufgeschlüsselt)
                        Audit_1_Relevance: auditLog["1_Relevance_Check"] || "",
                        Audit_2_Vision: auditLog["2_Vision_Check"] || "",
                        Audit_3_Syntax: auditLog["3_Syntax_Check"] || "",
                        Audit_4_Sovereignty: auditLog["4_Sovereignty_Check"] || "",
                        Audit_5_Museo: auditLog["5_Museo_Check"] || "",

                        // SCHLAGWORT-DATEN
                        Cluster: cluster,
                        Schlagwort: kw.term,
                        Status: kw.status,
                        GND_Name: kw.gnd_name || "",
                        GND_ID: kw.gnd_id || "",
                        Confidence: kw.confidence || "",
                        LLM2_Rationale: kw.llm2_rationale || "",
                        LLM3_Judge: kw.llm3_judge_comment || "",
                        LLM4_Reasoning: kw.llm4_reasoning || ""
                    }
                });
            }
        }
    }
}

// Gibt eine flache Liste aller Schlagworte zurück
return flattenedKeywords;

/*
=========================================================
JSON PARSER & DECOLONIAL VALIDATOR (v5 — Fehlerklassen-Entscheider)
1. Parst die LLM-Antwort; Fallback auf Leer-Skelett bei Parse-Fehler
2. DE-BIAS: nur 'term', exakter Ganzwort-Abgleich (REPLACE/CONTEXTUALIZE/DROP)
3. NEU: Status wird aus fehlerklassen BERECHNET (nicht mehr vom LLM)
   Präzedenz: Wegwerf > Reparier > Verschieben/grün
   FALSCHER_CLUSTER -> Code verschiebt ins correct_cluster (bleibt grün)
4. NEU: Code-Netze über die Grünen: DATIERUNG (Regex) + exakte Dopplung
5. NUR GRÜN -> payload_valid (GND); Gelb + Rot -> payload_rejected
=========================================================
*/

// ------------------------------------------------------
// TEIL A: KONFIGURATION
// ------------------------------------------------------
const DE_BIAS_MAP = {
  "Abendland": {"replacement": ["Westasien", "Europa"], "action": "CONTEXTUALIZE", "category": "Eurozentrismus"},
  "Abnormitätenschau": {"replacement": [], "action": "CONTEXTUALIZE", "category": "Ableismus"},
  "Afrikaner": {"replacement": ["Menschen des afrikanischen Kontinents"], "action": "CONTEXTUALIZE", "category": "Kolonialismus"},
  "Arisierung": {"replacement": ["Raub", "Enteignung"], "action": "CONTEXTUALIZE", "category": "NS-Unrecht"},
  "Australneger": {"replacement": ["Aborigine"], "action": "REPLACE", "category": "Rassismus"},
  "Bastard": {"replacement": ["Außereheliches Kind"], "action": "REPLACE", "category": "Abwertung"},
  "Behinderter": {"replacement": ["Mensch mit Behinderung"], "action": "REPLACE", "category": "Ableismus"},
  "Berber": {"replacement": ["Imazighen"], "action": "REPLACE", "category": "Kolonialismus"},
  "Buschleute": {"replacement": ["San", "Khoisan"], "action": "CONTEXTUALIZE", "category": "Kolonialismus"},
  "Buschneger": {"replacement": ["Maroons"], "action": "CONTEXTUALIZE", "category": "Rassismus"},
  "Drittes Reich": {"replacement": ["NS-Regime"], "action": "REPLACE", "category": "Nationalsozialismus"},
  "Dunkelhäutig": {"replacement": ["Schwarze Menschen", "PoC"], "action": "REPLACE", "category": "Rassismus"},
  "Eingeboren": {"replacement": ["Indigen"], "action": "REPLACE", "category": "Kolonialismus"},
  "Endlösung": {"replacement": ["Shoah", "Holocaust"], "action": "CONTEXTUALIZE", "category": "NS-Euphemismus"},
  "Eskimo": {"replacement": ["Inuit"], "action": "REPLACE", "category": "Kolonialismus"},
  "Exotisch": {"replacement": [], "action": "CONTEXTUALIZE", "category": "Exotismus"},
  "Farbig": {"replacement": [], "action": "DROP", "category": "Rassismus"},
  "Gastarbeiter": {"replacement": ["Arbeitsmigranten"], "action": "REPLACE", "category": "Migration"},
  "Gypsy": {"replacement": ["Roma", "Sinti"], "action": "CONTEXTUALIZE", "category": "Antiziganismus"},
  "Häuptling": {"replacement": ["Oberhaupt"], "action": "CONTEXTUALIZE", "category": "Kolonialismus"},
  "Hottentotte": {"replacement": ["Khoikhoi"], "action": "CONTEXTUALIZE", "category": "Rassismus"},
  "Indianer": {"replacement": ["Indigene Bevölkerung", "Native Americans"], "action": "REPLACE", "category": "Kolonialismus"},
  "Irrenanstalt": {"replacement": ["Psychiatrische Klinik"], "action": "REPLACE", "category": "Ableismus"},
  "Kristallnacht": {"replacement": ["Novemberpogrome"], "action": "REPLACE", "category": "NS-Euphemismus"},
  "Krüppel": {"replacement": ["Mensch mit Behinderung"], "action": "REPLACE", "category": "Ableismus"},
  "Mohr": {"replacement": ["Schwarzer Mensch"], "action": "CONTEXTUALIZE", "category": "Rassismus"},
  "Mongoloid": {"replacement": ["Person mit Trisomie 21"], "action": "REPLACE", "category": "Ableismus"},
  "Morgenland": {"replacement": ["Naher Osten"], "action": "CONTEXTUALIZE", "category": "Eurozentrismus"},
  "Mulatte": {"replacement": ["Person mit binationalem Hintergrund"], "action": "CONTEXTUALIZE", "category": "Rassismus"},
  "Muselmann": {"replacement": ["Muslim"], "action": "REPLACE", "category": "Islamfeindlichkeit"},
  "Naturvolk": {"replacement": ["Indigene Gemeinschaft"], "action": "REPLACE", "category": "Kolonialismus"},
  "Neger": {"replacement": ["Schwarzer Mensch", "PoC"], "action": "REPLACE", "category": "Rassismus"},
  "Orientalisch": {"replacement": ["Westasiatisch", "Arabisch"], "action": "REPLACE", "category": "Eurozentrismus"},
  "Rasse": {"replacement": [], "action": "DROP", "category": "Rassismus"},
  "Schwarzafrika": {"replacement": ["Subsahara-Afrika"], "action": "CONTEXTUALIZE", "category": "Rassismus"},
  "Taubstumm": {"replacement": ["Gehörlos"], "action": "REPLACE", "category": "Ableismus"},
  "Transsexuell": {"replacement": ["Transgeschlechtlich"], "action": "REPLACE", "category": "Gender"},
  "Zigeuner": {"replacement": ["Roma und Sinti"], "action": "REPLACE", "category": "Antiziganismus"},
  "Zwerg": {"replacement": ["Kleinwüchsiger Mensch"], "action": "REPLACE", "category": "Ableismus"}
};

// ------------------------------------------------------
// TEIL B: HELFER
// ------------------------------------------------------
function normalizeTerm(t) {
  return String(t === null || t === undefined ? "" : t).trim().toLowerCase();
}

const BIAS_LOOKUP = {};
for (const [key, rule] of Object.entries(DE_BIAS_MAP)) {
  BIAS_LOOKUP[normalizeTerm(key)] = { original: key, ...rule };
}

const META_KEYS = ["_decolonial_audit_log", "Protokoll_Status", "_provenance_critique", "Kritischer_Hinweis"];

const CLUSTERS = [
  "Objekttyp", "Thema_Phänomen", "Inhalt_Motiv", "Funktion_Zweck",
  "Visuelle_Merkmale", "Form_Gestalt", "Bestandteile", "Gebrauchskontext",
  "Kultureller_Kontext", "Emotion_Atmosphäre", "Farbe_Nuancen"
];

// Fehlerklassen -> Status
const DISCARD_CLASSES = new Set([
  "KEINE_EVIDENZ","HALLUZINATION","MATERIAL_PUR","MATERIAL_TECHNIK","DATIERUNG",
  "GEOGRAFIE_EIGENNAME","SPEKULATION_ZIRKEL","ASYMMETRIE","REDUNDANZ"
]);
const REPAIR_CLASSES = new Set(["PLURAL","ADJEKTIV","KOMPOSITUM","FEHLENDE_BRUECKE","MATERIAL_KOMPOSITUM"]);
const MOVE_CLASS = "FALSCHER_CLUSTER";

// Leer-Skelett bei unparsebarer LLM3-Antwort
function buildEmptySkeleton(note) {
  const skel = {
    _decolonial_audit_log: {
      "1_Relevance_Check": "", "2_Vision_Check": "", "3_Syntax_Check": "",
      "4_Sovereignty_Check": "", "5_Museo_Check": ""
    },
    Protokoll_Status: "Restricted Access (Check Local Contexts)",
    _provenance_critique: null,
    Kritischer_Hinweis: note
  };
  for (const c of CLUSTERS) skel[c] = [];
  return skel;
}

// DE-BIAS: prüft NUR term (exakter Ganzwort-Abgleich)
function applyBiasPolicyToTerms(parsedData, warningsList) {
  for (const [key, value] of Object.entries(parsedData)) {
    if (META_KEYS.includes(key) || !Array.isArray(value)) continue;
    const kept = [];
    for (const entry of value) {
      if (!entry || typeof entry.term !== "string") { kept.push(entry); continue; }
      const rule = BIAS_LOOKUP[normalizeTerm(entry.term)];
      if (!rule) { kept.push(entry); continue; }

      if (rule.action === "DROP") {
        warningsList.push(`Begriff '${entry.term}' automatisch entfernt (${rule.category}).`);
        continue;
      }
      if (rule.action === "REPLACE" && rule.replacement && rule.replacement.length > 0) {
        warningsList.push(`Begriff '${entry.term}' ersetzt durch '${rule.replacement[0]}' (${rule.category}).`);
        entry.term = rule.replacement[0];
        kept.push(entry);
        continue;
      }
      if (rule.action === "CONTEXTUALIZE") {
        if (!entry.term.includes("[sic!]")) entry.term = `${entry.term} [sic!]`;
        warningsList.push(`SENSITIV: Begriff '${rule.original}' markiert (${rule.category}).`);
        kept.push(entry);
        continue;
      }
      kept.push(entry);
    }
    parsedData[key] = kept;
  }
}

// Status aus fehlerklassen berechnen + FALSCHER_CLUSTER verschieben
function deriveStatusAndMove(parsedData) {
  const moves = [];
  for (const cluster of CLUSTERS) {
    const arr = Array.isArray(parsedData[cluster]) ? parsedData[cluster] : [];
    for (const it of arr) {
      if (!it || typeof it !== "object") continue;
      const flags = Array.isArray(it.fehlerklassen) ? it.fehlerklassen : [];

      let status = "green";
      if (flags.some(f => DISCARD_CLASSES.has(f))) status = "red";
      else if (flags.some(f => REPAIR_CLASSES.has(f))) status = "yellow";
      it.status = status;

      if (status !== "red" &&
          flags.includes(MOVE_CLASS) &&
          typeof it.correct_cluster === "string" &&
          CLUSTERS.includes(it.correct_cluster) &&
          it.correct_cluster !== cluster) {
        moves.push({ from: cluster, to: it.correct_cluster, item: it });
      }
    }
  }
  for (const m of moves) {
    const fromArr = parsedData[m.from];
    if (Array.isArray(fromArr)) {
      const idx = fromArr.indexOf(m.item);
      if (idx !== -1) fromArr.splice(idx, 1);
    }
    if (!Array.isArray(parsedData[m.to])) parsedData[m.to] = [];
    parsedData[m.to].push(m.item);
  }
}

// Deterministische Netze über die GRÜNEN: Datierung + exakte Dopplung
function applyGreenNets(parsedData, warningsList) {
  const DATE_RE = /\b\d{4}\b|jahrhundert|\bjh\.?\b|\b\d{2,4}er\b/i;
  const seen = new Set();
  for (const cluster of CLUSTERS) {
    const arr = Array.isArray(parsedData[cluster]) ? parsedData[cluster] : [];
    for (const it of arr) {
      if (!it || it.status !== "green" || typeof it.term !== "string") continue;

      if (DATE_RE.test(it.term)) {
        it.status = "red";
        it.judge_comment = (it.judge_comment ? it.judge_comment + " | " : "") + "CODE-NET: Datierung -> entfernt.";
        warningsList.push(`Datierung '${it.term}' per Code entfernt.`);
        continue;
      }

      const key = normalizeTerm(it.term);
      if (seen.has(key)) {
        it.status = "red";
        it.judge_comment = (it.judge_comment ? it.judge_comment + " | " : "") + "CODE-NET: exakte Dopplung -> entfernt.";
        warningsList.push(`Dopplung '${it.term}' per Code entfernt.`);
      } else {
        seen.add(key);
      }
    }
  }
}

// ------------------------------------------------------
// TEIL C: PARSING
// ------------------------------------------------------
const items = $input.all();
const outputItems = [];

function cleanAndParse(text) {
    if (!text) return { error: "Empty content" };
    let cleaned = text.replace(/^```json\s*/i, '').replace(/\s*```$/, '');
    const firstBrace = cleaned.indexOf('{');
    const lastBrace = cleaned.lastIndexOf('}');
    if (firstBrace !== -1 && lastBrace !== -1) {
        cleaned = cleaned.substring(firstBrace, lastBrace + 1);
    }
    try {
        return JSON.parse(cleaned);
    } catch (e) {
        try {
            const fixed = cleaned.replace(/\\"/g, '"');
            return JSON.parse(fixed);
        } catch (e2) {
            return { _parsing_error: true, raw_text: text };
        }
    }
}

// ------------------------------------------------------
// TEIL D: HAUPTSCHLEIFE
// ------------------------------------------------------
for (const item of items) {
    const json = item.json;

    // 1. PFAD-SUCHE
    let contentString = "";
    if (json.choices && json.choices[0] && json.choices[0].message) {
        contentString = json.choices[0].message.content;
    } else if (json.message && json.message.content) {
        contentString = json.message.content;
    } else if (json.response) {
        contentString = json.response;
    } else if (json.content && json.content.parts) {
        contentString = json.content.parts[0].text;
    } else {
        contentString = JSON.stringify(json);
    }

    // 2. PARSEN (+ Fallback)
    let parsedData = cleanAndParse(contentString);
    if (parsedData._parsing_error || parsedData.error) {
        const rawText = parsedData.raw_text || "";
        parsedData = buildEmptySkeleton("AUTO-FLAG: LLM3-Antwort nicht parsebar – Objekt ohne Tags durchgereicht.");
        parsedData._llm3_unparsable = true;
        parsedData._llm3_raw = rawText;
    }

    // 3. DE-BIAS -> STATUS BERECHNEN -> CODE-NETZE -> SPLIT
    {
        const warnings = [];
        applyBiasPolicyToTerms(parsedData, warnings);   // term-Bereinigung
        deriveStatusAndMove(parsedData);                // fehlerklassen -> status + Verschiebung
        applyGreenNets(parsedData, warnings);           // Datierung + Dopplung über die Grünen

        if (warnings.length > 0) {
            const existingNote = parsedData.Kritischer_Hinweis ? parsedData.Kritischer_Hinweis + " | " : "";
            const uniqueWarnings = [...new Set(warnings)];
            parsedData.Kritischer_Hinweis = existingNote + "AUTO-FLAG: " + uniqueWarnings.join(" ");
        }

        // NUR GRÜN -> payload_valid; GELB + ROT -> payload_rejected
        let payload_valid = {};
        let payload_rejected = {};
        let hasRedStatus = false;

        for (const key of META_KEYS) {
            if (parsedData[key] !== undefined) {
                payload_valid[key] = parsedData[key];
                payload_rejected[key] = parsedData[key];
            }
        }

        for (const [key, value] of Object.entries(parsedData)) {
            if (!META_KEYS.includes(key) && Array.isArray(value)) {
                const validItems = [];
                const rejectedItems = [];
                value.forEach(clusterItem => {
                    if (clusterItem && clusterItem.status === 'green') {
                        validItems.push(clusterItem);
                    } else {
                        rejectedItems.push(clusterItem);
                        hasRedStatus = true;
                    }
                });
                payload_valid[key] = validItems;
                payload_rejected[key] = rejectedItems;
            }
        }

        parsedData.payload_valid = payload_valid;
        parsedData.payload_rejected = payload_rejected;
        parsedData.has_red_status = hasRedStatus;
    }

    // 4. OUTPUT
    const newItem = {
        ...json,
        llm_result: parsedData,
        has_red_status: parsedData.has_red_status,
        ...parsedData
    };
    outputItems.push({ json: newItem });
}

return outputItems;

// =====================================================================
// CODE-NODE: Stufe 2 - Tagging (MIT BILD + MASTER CAPTION + 2 ROHE CAPTIONS)
// =====================================================================
const item = $input.item.json;

if (!item.rawSystempromptText) {
  throw new Error('Systemprompt fehlt');
}
if (!item.master_caption) {
  throw new Error('master_caption fehlt');
}
if (!item.context_data_string) {
  throw new Error('context_data_string fehlt');
}

// Bild laden
const imageUrl = item.Bildlink;
if (!imageUrl || !imageUrl.startsWith('http')) {
  throw new Error('Ungültige oder fehlende Bild-URL');
}
const imageResponse = await this.helpers.httpRequest({
  method: 'GET',
  url: imageUrl,
  encoding: 'arraybuffer'
});
const base64ImageString = Buffer.from(imageResponse).toString('base64');
const mimeType = imageUrl.toLowerCase().endsWith('.png') ? 'image/png' : 'image/jpeg';
const base64Payload = `data:${mimeType};base64,${base64ImageString}`;

const userPrompt = `Hier sind die Eingabedaten für das zu bearbeitende Objekt.
Wende die Regeln aus dem System-Prompt strikt an.
WICHTIG: Du erhältst das Originalbild, einen konsolidierten visuellen Befund (master_caption) sowie zwei rohe Ausgangsbefunde zur Verifikation. Nutze die master_caption als primäre Quelle. Die rohen Befunde dienen als Fallback wenn du am Bild etwas anderes siehst als die master_caption beschreibt. Was weder master_caption noch Bild belegen, tagge nicht.

=== DATENBASIS ===

[INPUT 1: KONSOLIDIERTER BEFUND – master_caption (primäre Quelle)]
Enthält am Ende zwei Pflicht-Abschnitte:
- Abschnitt 7 SENSITIVITÄTS-HINWEIS → steuert deinen Sovereignty-Check / Protokoll_Status.
- Abschnitt 8 KONFIDENZ/UNSICHERHEIT → als [unsicher] markierte Befunde nur zurückhaltend taggen, nie als harte Tatsache.
"""
${item.master_caption}
"""

[INPUT 2A: ROHER BEFUND – QUELLE A (Qwen, zur Verifikation)]
"""
${item.caption_1 || 'nicht verfügbar'}
"""

[INPUT 2B: ROHER BEFUND – QUELLE B (Gemma, zur Verifikation)]
"""
${item.caption_2 || 'nicht verfügbar'}
"""

[INPUT 3: MUSEUMSMETADATEN (Fakten)]
"""
${item.context_data_string}
"""`;

return {
  json: {
    model: "qwen3.6-27b-mtp",
    messages: [
      { role: "system", content: item.rawSystempromptText },
      { role: "user", content: [
        { type: "text", text: userPrompt },
        { type: "image_url", image_url: { url: base64Payload } }
      ]}
    ],
    temperature: 0.2,
    top_p: 0.8,
    top_k: 20,
    presence_penalty: 0.3,
    response_format: { type: "json_object" },
    chat_template_kwargs: { enable_thinking: false },
    max_tokens: 4096,
    // Durchreichen für nachgelagerte Nodes
    Bildlink: item.Bildlink,
    Image: item.Bildlink,
    object_metadata: item.object_metadata,
    context_data_string: item.context_data_string
  }
};

// =====================================================================
// CODE-NODE: LLM3-Audit-Body (json_schema-constrained, MIT Vision)
// v2: Judge gibt Fehlerklassen statt Status aus
// =====================================================================
const item = $input.item.json;
const MODEL = "gemma-4-31b-it";
const IMAGE_FIELD = "Image";   // ← Feldname deiner Bild-URL

const CLUSTERS = ["Objekttyp","Thema_Phänomen","Inhalt_Motiv","Funktion_Zweck",
