// Globale Dedupe + Datums-Netz wie applyGreenNets. Abgelehnte bleiben Gelb.
const CLUSTERS = ["Objekttyp","Thema_Phänomen","Inhalt_Motiv","Funktion_Zweck",
  "Visuelle_Merkmale","Form_Gestalt","Bestandteile","Gebrauchskontext",
  "Kultureller_Kontext","Emotion_Atmosphäre","Farbe_Nuancen"];
const META = ["_decolonial_audit_log","Protokoll_Status","_provenance_critique","Kritischer_Hinweis"];
const clone = o => JSON.parse(JSON.stringify(o||{}));
const norm  = s => (s||"").toString().trim().toLowerCase();
const DATE_RE = /\b\d{4}\b|jahrhundert|\bjh\.?\b|\b\d{2,4}er\b/i;

const base = $('Parse_LLM3_and_Debias').item.json;
const pvIn = clone(base.payload_valid);
const prIn = clone(base.payload_rejected);

const DROP = new Set(["farbig","rasse","exotisch","abnormitätenschau"]);
const REPLACE = {
  "neger":"Schwarzer Mensch","mohr":"Schwarzer Mensch","eskimo":"Inuit",
  "indianer":"Indigene Bevölkerung","zigeuner":"Roma und Sinti","gypsy":"Roma",
  "eingeboren":"Indigen","behinderter":"Mensch mit Behinderung","krüppel":"Mensch mit Behinderung",
  "zwerg":"Kleinwüchsiger Mensch","taubstumm":"Gehörlos","dunkelhäutig":"Schwarze Menschen",
  "gastarbeiter":"Arbeitsmigranten","muselmann":"Muslim","naturvolk":"Indigene Gemeinschaft",
  "mongoloid":"Person mit Trisomie 21","bastard":"Außereheliches Kind","transsexuell":"Transgeschlechtlich",
  "berber":"Imazighen","australneger":"Aborigine","drittes reich":"NS-Regime",
  "kristallnacht":"Novemberpogrome","irrenanstalt":"Psychiatrische Klinik"
};
function biasScreen(raw){
  const t=(raw||"").toString().trim(); if(!t) return null;
  const n=norm(t);
  if (DROP.has(n)) return {term:t, drop:true};
  if (REPLACE[n])  return {term:REPLACE[n], drop:false};
  return {term:t, drop:false};
}

function parseLLM(){
  const j=$input.item.json; let content="";
  if (j.choices && j.choices[0] && j.choices[0].message) content=j.choices[0].message.content;
  else if (j.body && j.body.choices) content=j.body.choices[0].message.content;
  else content=JSON.stringify(j);
  let c=(content||"").replace(/^```json\s*/i,'').replace(/\s*```$/,'');
  const a=c.indexOf('{'), b=c.lastIndexOf('}');
  if (a!==-1 && b!==-1) c=c.substring(a,b+1);
  try { return JSON.parse(c); } catch(e){ return null; }
}
const parsed  = parseLLM();
const repairs = (parsed && Array.isArray(parsed.repairs)) ? parsed.repairs : [];
const repMap  = {};
for (const r of repairs) repMap[ r.cluster + '||' + norm(r.original) ] = r;

const validAccum={}, rejectedAccum={};
for (const c of CLUSTERS){ validAccum[c]=[]; rejectedAccum[c]=[]; }
const seen = new Set();   // GLOBAL, wie applyGreenNets

// Pass 1: bestehende Grüne + Rote
for (const c of CLUSTERS){
  for (const g of (Array.isArray(pvIn[c])?pvIn[c]:[]))
    if (g && g.status!=='yellow'){ validAccum[c].push(g); seen.add(norm(g.term)); }
  for (const rd of (Array.isArray(prIn[c])?prIn[c]:[]))
    if (rd && rd.status!=='yellow') rejectedAccum[c].push(rd);
}

// Gelbe einsammeln (Move ist schon passiert -> source = aktueller Cluster)
const yellowItems=[];
for (const c of CLUSTERS)
  for (const src of [pvIn[c], prIn[c]])
    if (Array.isArray(src)) for (const t of src)
      if (t && t.status==='yellow') yellowItems.push({ y:t, source:c });

// Pass 2: reparieren
for (const {y, source} of yellowItems){
  const r = repMap[ source + '||' + norm(y.term) ];
  let folded=false;
  if (r && r.repairable && Array.isArray(r.repaired_terms) && r.repaired_terms.length){
    const target = (y.correct_cluster && CLUSTERS.includes(y.correct_cluster)) ? y.correct_cluster : source;
    for (const rt of r.repaired_terms){
      const s=biasScreen(rt);
      if (!s || s.drop) continue;
      if (!s.term || DATE_RE.test(s.term) || seen.has(norm(s.term))) continue;
      seen.add(norm(s.term));
      validAccum[target].push({ term:s.term, why:y.why||"", status:"green", judge_comment:"", _repaired_from:y.term });
      folded=true;
    }
  }
  if (!folded) rejectedAccum[source].push(y);   // bleibt gelb
}

const newValid={}, newRejected={};
for (const k of META){ if (pvIn[k]!==undefined) newValid[k]=pvIn[k]; if (prIn[k]!==undefined) newRejected[k]=prIn[k]; }
for (const c of CLUSTERS){ newValid[c]=validAccum[c]; newRejected[c]=rejectedAccum[c]; }
return { json: { ...base, payload_valid:newValid, payload_rejected:newRejected } };
